// Using environment variables and Secrets Manager
const { SecretsManager } = require('aws-sdk');
const secretsManager = new SecretsManager();

let dbCredentials = null;

// Cache secrets outside handler for reuse across warm starts
async function getCredentials() {
  if (dbCredentials) return dbCredentials;
  const secret = await secretsManager
    .getSecretValue({ SecretId: process.env.DB_SECRET_ARN })
    .promise();
  dbCredentials = JSON.parse(secret.SecretString);
  return dbCredentials;
}

exports.handler = async (event) => {
  const creds = await getCredentials();
  // Use creds.username, creds.password to connect to DB
  console.log("Environment:", process.env.NODE_ENV);
};
